import{_ as n,o as s,c as l,j as a,a as t}from"./chunks/framework.CVjg771q.js";const f=JSON.parse('{"title":"生肖 · 兔","description":"卯兔——机敏好动，温顺可爱","frontmatter":{"pageClass":"dao-changshi-page","aside":false,"title":"生肖 · 兔","description":"卯兔——机敏好动，温顺可爱"},"headers":[],"relativePath":"changshi/shengxiao/tu.md","filePath":"changshi/shengxiao/tu.md","lastUpdated":1779783531000}'),r={name:"changshi/shengxiao/tu.md"};function o(i,e,c,d,h,p){return s(),l("div",null,[...e[0]||(e[0]=[a("h1",{id:"卯兔",tabindex:"-1"},[t("卯兔 "),a("a",{class:"header-anchor",href:"#卯兔","aria-label":'Permalink to "卯兔"'},"​")],-1),a("blockquote",null,[a("p",null,"地支「卯」· 卯时（05:00–07:00）· 五行属木 · 阴阳为阴")],-1),a("p",null,"兔外表温顺可爱，实则机敏好动。卯时，玉兔（月亮）的光辉还未隐退。兔子依靠灵敏的听觉和视觉时刻保持警惕，危险来临时能以迅雷不及掩耳的速度逃走。因善于挖掘复杂洞穴，兔子还象征着具有迷惑或应急能力的人——「狡兔三窟」。兔子与月亮紧密相连，传说玉兔是嫦娥的宠物，在月宫负责捣药，由此兔子也成为长寿的象征。",-1),a("h2",{id:"生肖故事-骄傲的长跑健将",tabindex:"-1"},[t("生肖故事：骄傲的长跑健将 "),a("a",{class:"header-anchor",href:"#生肖故事-骄傲的长跑健将","aria-label":'Permalink to "生肖故事：骄傲的长跑健将"'},"​")],-1),a("p",null,"相传兔子和牛是邻居。听说玉皇大帝在选生肖，它们都想参与。牛知道兔子是长跑健将，虚心请教秘诀。兔子骄傲地说：「牛大哥，长跑是要靠天赋的，你看我后腿比前腿长得多，又身轻体便，你这大块头恐怕很难学会。」",-1),a("p",null,"憨厚的牛听了心都凉了半截，但它有韧劲——夜以继日地练习，无论刮风下雨都不间断，最终练就了四只铁蹄。到了排生肖的日子，兔子起得早跑得快，把其他动物甩在身后。兔子心想：「我今天起得最早、跑得最快，就算睡个回笼觉再走，头名也非我莫属。」于是跳进草丛呼呼大睡起来。",-1),a("p",null,"等被一阵急促的脚步声惊醒，定睛一看——老虎经过了身边！兔子这下急了，撒腿就跑，可紧赶慢赶还是落在了老虎之后。而牛虽然落后，凭着坚韧的毅力和平时练就的铁蹄，一鼓作气率先跑到了天宫。兔子虽然排上了生肖，但一想到之前对牛大哥的讽刺，就觉得脸上无光，回家后把家搬到了土洞中。直到现在，野兔依然住在土洞中。",-1)])])}const m=n(r,[["render",o]]);export{f as __pageData,m as default};
